const CameraCapture = ({ onCapture, onClose }) => {
  const [stream, setStream] = useState(null);
  const [isCaptured, setIsCaptured] = useState(false);
  const [capturedImage, setCapturedImage] = useState(null);
  const [error, setError] = useState(null);
  const [facingMode, setFacingMode] = useState('environment');
  const [isLoading, setIsLoading] = useState(false);

  const videoRef = useRef(null);
  const canvasRef = useRef(null);

  const startCamera = useCallback(async () => {
    try {
      setError(null);
      setIsLoading(true);

      // Stop existing stream
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }

      // Check for camera support
      if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        throw new Error('Camera khÃ´ng Ä‘Æ°á»£c há»— trá»£ trÃªn trÃ¬nh duyá»‡t nÃ y. Vui lÃ²ng sá»­ dá»¥ng Chrome, Firefox hoáº·c Safari má»›i nháº¥t.');
      }

      // Request camera access with better constraints for desktop
      const constraints = {
        video: {
          width: { ideal: 1280, min: 640 },
          height: { ideal: 720, min: 480 },
          frameRate: { ideal: 30, max: 60 }
        }
      };

      // Try different camera sources
      try {
        const mediaStream = await navigator.mediaDevices.getUserMedia(constraints);
        setStream(mediaStream);

        if (videoRef.current) {
          videoRef.current.srcObject = mediaStream;
          videoRef.current.play();
        }

        setIsLoading(false);
      } catch (err) {
        // Fallback to basic constraints
        const basicConstraints = { video: true };
        const mediaStream = await navigator.mediaDevices.getUserMedia(basicConstraints);
        setStream(mediaStream);

        if (videoRef.current) {
          videoRef.current.srcObject = mediaStream;
          videoRef.current.play();
        }

        setIsLoading(false);
      }
    } catch (err) {
      console.error('Camera error:', err);
      let errorMessage = 'KhÃ´ng thá»ƒ truy cáº­p camera. ';

      if (err.name === 'NotAllowedError') {
        errorMessage += 'Vui lÃ²ng cho phÃ©p truy cáº­p camera trong trÃ¬nh duyá»‡t.';
      } else if (err.name === 'NotFoundError') {
        errorMessage += 'KhÃ´ng tÃ¬m tháº¥y camera trÃªn thiáº¿t bá»‹.';
      } else if (err.name === 'NotSupportedError') {
        errorMessage += 'TrÃ¬nh duyá»‡t khÃ´ng há»— trá»£ camera.';
      } else {
        errorMessage += err.message;
      }

      setError(errorMessage);
      setIsLoading(false);
    }
  }, [stream]);

  const stopCamera = useCallback(() => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
  }, [stream]);

  const capturePhoto = useCallback(() => {
    if (!videoRef.current || !canvasRef.current) return;

    const video = videoRef.current;
    const canvas = canvasRef.current;
    const context = canvas.getContext('2d');

    // Set canvas size to video size
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;

    // Draw video frame to canvas (mirror the image)
    context.save();
    context.scale(-1, 1);
    context.drawImage(video, -canvas.width, 0, canvas.width, canvas.height);
    context.restore();

    // Convert to blob
    canvas.toBlob((blob) => {
      if (blob) {
        const imageUrl = URL.createObjectURL(blob);
        setCapturedImage(imageUrl);
        setIsCaptured(true);
        stopCamera();
      }
    }, 'image/jpeg', 0.9);
  }, [stopCamera]);

  const retakePhoto = useCallback(() => {
    setIsCaptured(false);
    setCapturedImage(null);
    if (capturedImage) {
      URL.revokeObjectURL(capturedImage);
    }
    startCamera();
  }, [startCamera, capturedImage]);

  const usePhoto = useCallback(() => {
    if (capturedImage) {
      // Convert blob URL to file
      fetch(capturedImage)
        .then(res => res.blob())
        .then(blob => {
          const file = new File([blob], 'camera-capture.jpg', { type: 'image/jpeg' });
          onCapture(capturedImage, file);
          onClose();
        });
    }
  }, [capturedImage, onCapture, onClose]);

  const switchCamera = useCallback(() => {
    // Only switch on mobile devices
    if (navigator.userAgent.match(/Android|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i)) {
      setFacingMode(prev => prev === 'user' ? 'environment' : 'user');
    } else {
      // On desktop, just restart camera
      startCamera();
    }
  }, [startCamera]);

  // Start camera when component mounts
  useEffect(() => {
    startCamera();

    return () => {
      stopCamera();
    };
  }, [startCamera, stopCamera]);

  // Restart camera when facing mode changes
  useEffect(() => {
    if (stream) {
      stopCamera();
      setTimeout(() => {
        startCamera();
      }, 100);
    }
  }, [facingMode]);

  if (error) {
    return (
      <CameraOverlay>
        <CameraHeader>
          <CloseButton onClick={onClose}>
            <X size={24} />
          </CloseButton>
          <CameraTitle>Camera</CameraTitle>
        </CameraHeader>
        <ErrorMessage>
          <ErrorTitle>
            <AlertCircle size={24} />
            KhÃ´ng thá»ƒ truy cáº­p camera
          </ErrorTitle>
          <ErrorText>{error}</ErrorText>
          <RetryButton onClick={startCamera}>
            Thá»­ láº¡i
          </RetryButton>
        </ErrorMessage>
      </CameraOverlay>
    );
  }

  if (isCaptured && capturedImage) {
    return (
      <CameraOverlay>
        <PreviewContainer>
          <PreviewImage src={capturedImage} alt="Captured" />
          <PreviewControls>
            <ActionButton className="retake" onClick={retakePhoto}>
              <RotateCcw size={20} />
              Chá»¥p láº¡i
            </ActionButton>
            <ActionButton className="use" onClick={usePhoto}>
              <Check size={20} />
              Sá»­ dá»¥ng áº£nh
            </ActionButton>
          </PreviewControls>
        </PreviewContainer>
      </CameraOverlay>
    );
  }

  return (
    <CameraOverlay>
      <CameraHeader>
        <CloseButton onClick={onClose}>
          <X size={24} />
        </CloseButton>
        <CameraTitle>Chá»¥p áº£nh sÃ¢u háº¡i</CameraTitle>
        <SwitchButton onClick={switchCamera} title="Chuyá»ƒn Ä‘á»•i camera">
          <RotateCcw size={20} />
        </SwitchButton>
      </CameraHeader>

      <CameraView>
        {isLoading && <LoadingSpinner />}
        <Video
          ref={videoRef}
          autoPlay
          playsInline
          muted
        />
        <Canvas ref={canvasRef} />
      </CameraView>

      <CameraControls>
        <CaptureButton onClick={capturePhoto}>
          <InnerCircle />
        </CaptureButton>
      </CameraControls>
    </CameraOverlay>
  );
};

